console.log('[EDUCATIONAL DEMO] This demonstrates how SVG files can execute arbitrary JavaScript');

// Simulate a harmless "attack" for educational purposes
var demoData = {
  timestamp: new Date().toISOString(),
  userAgent: navigator.userAgent,
  location: window.location.href,
  cookies: document.cookie ? 'Cookies present' : 'No cookies found',
  localStorage: localStorage.length > 0 ? 'Local storage present' : 'No local storage'
};

