// Display educational message instead of actual attack
var demoDiv = document.createElement('div');
demoDiv.style.cssText = 'position:fixed;top:10px;right:10px;background:#ff6b6b;color:white;padding:10px;border-radius:5px;z-index:9999;font-family:Arial;font-size:12px;max-width:300px;';
